/**
 * Isolates the factorized row (non-aggregate SELECT) path on star and two-hop shapes: hubs fanning out over two
 * predicates, plus a chain whose middle nodes are shared so per-key probe memoization is exercised. Run twice — once
 * as-is and once with {@code -Drdf4j.lmdb.factorizedRows.enabled=false} — to compare against the enumerating baseline.
 * Each invocation verifies the expected row count, so a wrong factorized result fails the run.
 */
@State(Scope.Benchmark)
@Warmup(iterations = 4, time = 2, timeUnit = TimeUnit.SECONDS)
@BenchmarkMode({ Mode.AverageTime })
@Fork(value = 1, jvmArgs = { "-Xms1G", "-Xmx4G" })
@Measurement(iterations = 4, batchSize = 1, time = 2, timeUnit = TimeUnit.SECONDS)
@OutputTimeUnit(TimeUnit.MILLISECONDS)
public class FactorizedRowsStarBenchmark {

	private static final String EX = "http://example.com/";
	private static final int HUBS = 1_000;
	private static final int P1_FANOUT = 10;
	private static final int P2_FANOUT = 100;
	private static final int P2_DISTINCT_VALUES = 500;
	private static final int A_DISTINCT_VALUES = 2_000;
	private static final int P3_FANOUT = 10;

	@Param({
			"selectHub",
			"selectDistinctHub",
			"selectTails",
			"selectDistinctTail",
			"selectTwoHopLeaf"
	})
	public String variant;

	private java.io.File dataDir;
	private SailRepository repository;
	private String query;
	private long expectedRows;

	@Setup(Level.Trial)
	public void setUp() {
		dataDir = Files.newTemporaryFolder();
		repository = new SailRepository(new LmdbStore(dataDir, new LmdbStoreConfig("spoc,posc,ospc")));
		try (SailRepositoryConnection conn = repository.getConnection()) {
			ValueFactory vf = conn.getValueFactory();
			IRI p1 = vf.createIRI(EX, "p1");
			IRI p2 = vf.createIRI(EX, "p2");
			IRI p3 = vf.createIRI(EX, "p3");
			conn.begin();
			for (int hub = 0; hub < HUBS; hub++) {
				IRI subject = vf.createIRI(EX, "hub" + hub);
				for (int i = 0; i < P1_FANOUT; i++) {
					// middle nodes are shared across hubs so two-hop probes repeat keys
					conn.add(subject, p1, vf.createIRI(EX, "a" + ((hub * P1_FANOUT + i) % A_DISTINCT_VALUES)));
				}
				for (int i = 0; i < P2_FANOUT; i++) {
					conn.add(subject, p2, vf.createIRI(EX, "b" + ((hub * P2_FANOUT + i) % P2_DISTINCT_VALUES)));
				}
			}
			for (int a = 0; a < A_DISTINCT_VALUES; a++) {
				IRI middle = vf.createIRI(EX, "a" + a);
				for (int i = 0; i < P3_FANOUT; i++) {
					conn.add(middle, p3, vf.createIRI(EX, "c" + (a * P3_FANOUT + i)));
				}
			}
			conn.commit();
		}
		long starSolutions = (long) HUBS * P1_FANOUT * P2_FANOUT;
		switch (variant) {
		case "selectHub":
			query = star("?s");
			expectedRows = starSolutions;
			break;
		case "selectDistinctHub":
			query = star("DISTINCT ?s");
			expectedRows = HUBS;
			break;
		case "selectTails":
			query = star("?a ?b");
			expectedRows = starSolutions;
			break;
		case "selectDistinctTail":
			query = star("DISTINCT ?b");
			expectedRows = P2_DISTINCT_VALUES;
			break;
		case "selectTwoHopLeaf":
			query = "PREFIX ex: <" + EX + ">\n"
					+ "SELECT ?s ?c WHERE {\n"
					+ "  ?s ex:p1 ?a .\n"
					+ "  ?a ex:p3 ?c .\n"
					+ "}";
			expectedRows = (long) HUBS * P1_FANOUT * P3_FANOUT;
			break;
		default:
			throw new IllegalArgumentException(variant);
		}
	}

	private static String star(String select) {
		return "PREFIX ex: <" + EX + ">\n"
				+ "SELECT " + select + " WHERE {\n"
				+ "  ?s ex:p1 ?a .\n"
				+ "  ?s ex:p2 ?b .\n"
				+ "}";
	}

	@TearDown(Level.Trial)
	public void tearDown() throws IOException {
		repository.shutDown();
		FileUtil.deleteDir(dataDir);
	}

	@Benchmark
	public long executeQuery() {
		try (SailRepositoryConnection conn = repository.getConnection()) {
			List<BindingSet> result = QueryResults.asList(conn.prepareTupleQuery(query).evaluate());
			if (result.size() != expectedRows) {
				throw new IllegalStateException(variant + ": expected " + expectedRows + " rows but got "
						+ result.size());
			}
			return result.size();
		}
	}

	public static void main(String[] args) throws RunnerException {
		Options opt = new OptionsBuilder()
				.include("FactorizedRowsStarBenchmark")
				.build();
		new Runner(opt).run();
	}
}
